import datetime

# Load case assignment counts
assignment_data = locals()['var_functions.query_db:20']

# Get cases with exactly 1 owner assignment (non-transferred)
single_owner_caseids = []
for row in assignment_data:
    if int(row['assignment_count']) == 1:
        single_owner_caseids.append(row['caseid__c'])

print("Cases with single owner assignment: %d" % len(single_owner_caseids))

# Load closed cases from past 4 months
closed_cases = locals()['var_functions.query_db:10']

# Find intersection - cases that are closed in past 4 months AND have single owner
single_owner_set = set(single_owner_caseids)
closed_case_ids = set([case['id'].lstrip('#') for case in closed_cases])

valid_cases = single_owner_set.intersection(closed_case_ids)
print("Cases that are closed in past 4 months AND have single owner: %d" % len(valid_cases))

# Build lookup for case to owner
assignment_lookup = {}
for row in assignment_data:
    if int(row['assignment_count']) == 1:
        assignment_lookup[row['caseid__c']] = row['newvalue__c']

# Get full details for valid cases  
valid_case_details = []
for case in closed_cases:
    case_id_clean = case['id'].lstrip('#')
    if case_id_clean in valid_cases:
        ownerid = assignment_lookup.get(case_id_clean, '')
        valid_case_details.append({
            'caseid': case_id_clean,
            'ownerid': ownerid.lstrip('#') if ownerid else None,
            'createddate': case['createddate'],
            'closeddate': case['closeddate']
        })

print("Valid case details retrieved: %d" % len(valid_case_details))

# Now calculate handle time in minutes
def calculate_handle_time(created_str, closed_str):
    if not created_str or not closed_str or created_str == 'None' or closed_str == 'None':
        return None
    try:
        created = datetime.datetime.fromisoformat(created_str.replace('Z', '+00:00'))
        closed = datetime.datetime.fromisoformat(closed_str.replace('Z', '+00:00'))
        if closed <= created:
            return None
        return int((closed - created).total_seconds() / 60)
    except:
        return None

# Calculate handle times and group by agent
cases_by_agent = {}
for case in valid_case_details:
    handle_time = calculate_handle_time(case['createddate'], case['closeddate'])
    if handle_time is None or handle_time <= 0:
        continue

    agent_id = case['ownerid']
    if not agent_id:
        continue

    if agent_id not in cases_by_agent:
        cases_by_agent[agent_id] = []
    cases_by_agent[agent_id].append(handle_time)

print("Agents with valid cases: %d" % len(cases_by_agent))

# Filter agents with more than 1 case and calculate average handle time
agent_stats = []
for agent_id, handle_times in cases_by_agent.items():
    if len(handle_times) > 1:
        avg_time = sum(handle_times) / len(handle_times)
        agent_stats.append({
            'agent_id': agent_id,
            'case_count': len(handle_times),
            'avg_handle_time': avg_time,
            'handle_times': handle_times
        })

print("Agents with more than 1 case: %d" % len(agent_stats))

# Find agent with lowest average handle time
if agent_stats:
    agent_stats.sort(key=lambda x: x['avg_handle_time'])
    best_agent = agent_stats[0]
    print("Best agent: %s with avg handle time %d minutes" % (best_agent['agent_id'], best_agent['avg_handle_time']))

    result = {
        'agent_id': best_agent['agent_id'],
        'avg_handle_time': round(best_agent['avg_handle_time'], 2),
        'case_count': best_agent['case_count']
    }
else:
    result = None

print('__RESULT__:')
print(json.dumps(result) if result else json.dumps({'error': 'No agents meet criteria'}))"}

