        return None
    try:
        return datetime.datetime.fromisoformat(date_str.replace('Z', '+00:00'))
    except:
        return None

for case in closed_cases:
    case_id = case['id'].lstrip('#')

    # Get the proper owner from casehistory, not from Case table
    owner_id = owner_lookup.get(case_id)
