    closed_date = parse_date(case['closeddate'])

    if not created_date or not closed_date:
        print("Invalid dates for case %s" % case_id)
        continue

    if closed_date <= created_date:
        print("Invalid date order for case %s" % case_id)
        continue

    # Calculate handle time in minutes
    handle_time_minutes = int((closed_date - created_date).total_seconds() / 60)

    if handle_time_minutes <= 0:
        continue

    # Store case data
    handle_time_data.append({
        'caseid': case_id,
        'ownerid': owner_id,
        'handle_time_minutes': handle_time_minutes
    })

    # Group by agent
